//-----------------------------------------------------------------------------
// MRFPointVent : SetTopSurface
//Input: const CATBaseUnknown_var &ispSurface
//Function: Sets the input ispSurface into feature
//-----------------------------------------------------------------------------
HRESULT MRFPointVent::SetRefSurface(const CATBaseUnknown_var & ispSurface)
{
	HRESULT rc = E_FAIL;
	CATFmFeatureFacade FeatFacadeOnPV(_CredentialForPV, this);

	if ((ispSurface != NULL_var) && (!!FeatFacadeOnPV))//Check input
	{
		// Valuate attribute key
		CATFmAttributeName AttrKey;
		CATFmAttributeValue FmAttrValue;

		AttrKey = CATFmAttributeName(_MRFPointVentRefSurface);
		rc = FeatFacadeOnPV.GetValue(AttrKey, FmAttrValue);
		FeatFacadeOnPV.UnsetValue(AttrKey);

		// Get input Curve feature facade
		CATFmFeatureFacade FeatFacadeOnSurface;
		FeatFacadeOnSurface = ispSurface;

		if (!!FeatFacadeOnSurface && SUCCEEDED(rc))
		{
			FmAttrValue.Clear();
			FmAttrValue.SetFeature(FeatFacadeOnSurface);

			// Set the feature attribute
			rc = FeatFacadeOnPV.SetValue(AttrKey, FmAttrValue);
		}
	}
	return rc;
}

//-----------------------------------------------------------------------------
// MRFPointVent : GetRefSurface
//Output: CATBaseUnknown_var & ospSurface
//Function: Retrieves the Reference Surface
//-----------------------------------------------------------------------------
HRESULT MRFPointVent::GetRefSurface(CATBaseUnknown_var & ospSurface)
{
	HRESULT rc = E_FAIL;
	CATFmFeatureFacade FeatFacadeOnPV(_CredentialForPV, this);

	if (!!FeatFacadeOnPV)
	{
		CATFmAttributeName AttrKey;
		CATFmAttributeValue FmAttrValue;
		AttrKey = CATFmAttributeName(_MRFPointVentRefSurface);
		rc = FeatFacadeOnPV.GetValue(AttrKey, FmAttrValue);

		if (SUCCEEDED(rc))
		{
			// Get the Curve feature facade
			CATFmFeatureFacade FeatFacadeOnSurface;
			rc = FmAttrValue.GetFeature(FeatFacadeOnSurface);

			if (SUCCEEDED(rc))
				rc = FeatFacadeOnSurface.QueryInterfaceOnFeature(IID_CATBaseUnknown, (void**)& ospSurface);
		}
	}
	return rc;
}

