//-----------------------------------------------------------------------------
// MRFPointVent : UpdateFeature
//Function: update the created feature.
//-----------------------------------------------------------------------------
void MRFPointVent::UpdateFeature()
{
	CATFmFeatureFacade FeatFacadeOnPointVent(_CredentialForPV, this);
	HRESULT rc = FeatFacadeOnPointVent.IsUpToDate();
	if (S_FALSE == rc)
	{
		rc = FeatFacadeOnPointVent.Update();
		if (SUCCEEDED(rc))
		{
			CATBaseUnknown *pPointVentObject = NULL;
			rc = FeatFacadeOnPointVent.QueryInterfaceOnFeature(IID_CATBaseUnknown, (void**)&pPointVentObject);
			if (SUCCEEDED(rc) && NULL != pPointVentObject)
			{
				CATPrtUpdateCom *pUpdateCommand = new CATPrtUpdateCom(pPointVentObject, 0, 0);
				
				pPointVentObject->Release();
				pPointVentObject = NULL;
			}
		}
	}
}